<script>
import axios from 'axios'
var loc = window.location.pathname.split('/').slice(-1)[0];

export default {
	name: "App",
	metaInfo: {
		title: "card.syui.ai",
		titleTemplate: '%s | ' + loc,
		meta: [
			{property: 'og:title', content: '%s | ' + loc}
		]
	},
	data () {
		return {
			all: null,
			card: null,
			cards: null,
			loc: window.location.pathname.split('/').slice(-1)[0],
			id: null,
			record: null,
			url: null,
			user: null,
			userid: null,
			ucard: null,
			status: null,
			premium: false,
			premium_text: null,
			rcards: null,
			fanarts: null,
			photos: null,
			info: false,
		}
	},
	mounted() {
		if (loc === 'owner'){
			axios
				.get("/json/card.json")
				.then(response => (this.rcards = response));
				if (loc.length > 1){
					axios
						.get(url,{ crossdomain: true })
						.then(response => (this.cards = response));
				
				}
		} else if (loc === 'te'){
			axios
				.get("/json/card.json")
				.then(response => (this.rcards = response));
				if (loc.length > 1){
					axios
						.get(url,{ crossdomain: true })
						.then(response => (this.cards = response));

				}
		} else if (loc === 'fa'){
			axios
				.get("/json/fanart.json")
				.then(response => (this.fanarts = response));
		} else if (loc === 'ph'){
			axios
				.get("/json/photo.json")
				.then(response => (this.photos = response));
		} else {
			axios.get("https://cors-card.herokuapp.com/https://api.syui.ai/users?itemsPerPage=2000",{ crossdomain: true })
				.then(response => { 
				this.record = response;
				this.id = this.record.data.find((v) => v.username == loc).id;
				let url = "https://cors-card.herokuapp.com/https://api.syui.ai/users/" + this.id + "/card?itemsPerPage=2000";
				axios
					.get("/json/card.json")
					.then(response => (this.rcards = response));
					if (loc.length > 1){
						axios
							.get(url,{ crossdomain: true })
							.then(response => { this.cards = response
													for (let i = 1; i <= 14; i++) {
														this.all = this.cards.data.some(
															b => b.card === i,
															);
															if (this.all === false) {
																break;
															}
													}
							});
					}
			})
			.catch(error => console.log(error));
		}},
		methods: {
			submit() {
				let url = "https://cors-card.herokuapp.com/https://api.syui.ai/users/" + this.id + "/card?itemsPerPage=2000";
				axios
					.get(url,{ crossdomain: true })
					.then(response => (this.cards = response));
					axios
						.get("https://cors-card.herokuapp.com/https://api.syui.ai/users/" + this.id,{ crossdomain: true })
						.then(response => (this.user = response));

			},
			page() {
				this.id = this.record.data.find((v) => v.username == this.userid).id;
				let url = "https://cors-card.herokuapp.com/https://api.syui.ai/users/" + this.id + "/card?itemsPerPage=2000";
				axios
					.get(url,{ crossdomain: true })
					.then(response => (this.ucard = response));
					//window.location.href = '/' + this.user;
			},
			sort(){
				if (this.premium) {
					this.premium = false;
					let url = "https://cors-card.herokuapp.com/https://api.syui.ai/users/" + this.id + "/card?itemsPerPage=2000";
					axios
						.get(url,{ crossdomain: true })
						.then(response => (this.cards = response));
				}
				return this.cards.data.sort((a, b) => {
					return b.cp - a.cp;
				});
			},
			sortcard(){
				if (this.premium) {
					this.premium = false;
					let url = "https://cors-card.herokuapp.com/https://api.syui.ai/users/" + this.id + "/card?itemsPerPage=2000";
					axios
						.get(url,{ crossdomain: true })
						.then(response => (this.cards = response));
				}
				return this.cards.data.sort((a, b) => {
					return b.card - a.card;
				});
			},
			cardinfo(){
					this.info = true;
			},
			cardpremium(){
				return this.cards.data.sort((a,b) => {
					this.premium = true;
					if (a.card === 15) {
						a.url = "[unavailable] card == 15";
					} else if (a.card === 16) {
						a.url = "[unavailable] card == 16";
					} else if (a.card === 17) {
						a.url = "[unavailable] card == 17";
					} else if (a.card === 18) {
						a.url = "[unavailable] card == 18";
					} else if (a.card === 19) {
						a.url = "[unavailable] card == 19";
					} else if (a.card === 22) {
						a.url = "[unavailable] card == 22";
					} else if (a.card === 23) {
						a.url = "[unavailable] card == 23";
					} else if (a.card >= 1 && a.cp < 50 ) {
						a.url = "[unavailable] rare cp < 50";
						return b.card - a.card;
					} else if (b.card === 0 && b.cp > 350) {
						a.url = "[unavailable] normal cp > 350";
						return b.card - a.card;
					} else if (a.cp === 0) {
						a.url = "[unavailable] cp == 0";
						return b.card - a.card;
					} else if (a.card === 0 && a.status === "super") {
						a.url = "[unavailable] normal == super";
						return b.card - a.card;
					} else {
						a.url = null;
						a.card = null;
						return
					}
				});
			}
		}
}
</script>

